import time
import random
import anthropic

client = anthropic.Anthropic(max_retries=0)  # manage retries ourselves

def backoff_jitter(attempt: int, base: float = 1.0, cap: float = 60.0) -> float:
    """Full jitter: sleep = uniform(0, min(cap, base * 2^attempt))."""
    return random.uniform(0, min(cap, base * (2 ** attempt)))

def call_api(messages: list, max_attempts: int = 6) -> anthropic.types.Message:
    for attempt in range(max_attempts):
        try:
            return client.messages.create(
                model="claude-sonnet-4-6",
                max_tokens=1024,
                messages=messages,
            )
        except anthropic.RateLimitError as e:
            if attempt == max_attempts - 1:
                raise
            # Prefer the server-provided retry-after over our formula
            retry_after = e.response.headers.get("retry-after")
            if retry_after:
                wait = float(retry_after) + random.uniform(0, 1)
            else:
                wait = backoff_jitter(attempt)
            print(f"429 on attempt {attempt + 1}, waiting {wait:.2f}s")
            time.sleep(wait)
        except (anthropic.InternalServerError, anthropic.APIConnectionError) as e:
            if attempt == max_attempts - 1:
                raise
            wait = backoff_jitter(attempt)
            print(f"{type(e).__name__} on attempt {attempt + 1}, waiting {wait:.2f}s")
            time.sleep(wait)

import time
import anthropic
from enum import Enum

class State(Enum):
    CLOSED = "closed"        # normal: requests pass through
    OPEN = "open"            # tripped: requests fail fast
    HALF_OPEN = "half_open"  # probing: one test request allowed

class CircuitBreaker:
    def __init__(
        self,
        failure_threshold: int = 5,
        recovery_timeout: float = 60.0,
    ):
        self.threshold = failure_threshold
        self.timeout = recovery_timeout
        self._state = State.CLOSED
        self._failures = 0
        self._opened_at: float | None = None

    def call(self, fn, *args, **kwargs):
        if self._state == State.OPEN:
            elapsed = time.monotonic() - self._opened_at
            if elapsed >= self.timeout:
                self._state = State.HALF_OPEN
            else:
                raise RuntimeError(
                    f"Circuit OPEN — retry in {self.timeout - elapsed:.0f}s"
                )

        try:
            result = fn(*args, **kwargs)
            self._on_success()
            return result
        except (anthropic.RateLimitError, anthropic.OverloadedError,
                anthropic.InternalServerError) as e:
            self._on_failure()
            raise

    def _on_success(self):
        self._failures = 0
        self._state = State.CLOSED

    def _on_failure(self):
        self._failures += 1
        if self._failures >= self.threshold:
            self._state = State.OPEN
            self._opened_at = time.monotonic()
            print(f"Circuit OPEN after {self._failures} failures")

client = anthropic.Anthropic(max_retries=0)
cb = CircuitBreaker(failure_threshold=5, recovery_timeout=60)

def make_request(prompt: str):
    return cb.call(
        client.messages.create,
        model="claude-sonnet-4-6",
        max_tokens=256,
        messages=[{"role": "user", "content": prompt}],
    )

import time
import random
import anthropic

client = anthropic.Anthropic(max_retries=0)

def call_with_overload_handling(messages: list, max_attempts: int = 5):
    for attempt in range(max_attempts):
        try:
            return client.messages.create(
                model="claude-sonnet-4-6",
                max_tokens=512,
                messages=messages,
            )
        except anthropic.RateLimitError as e:
            if attempt == max_attempts - 1:
                raise
            wait = float(e.response.headers.get("retry-after", 2 ** attempt))
            time.sleep(wait + random.uniform(0, 1))
        except anthropic.OverloadedError:
            if attempt == max_attempts - 1:
                raise
            # Back off more aggressively for overload — 10s, 20s, 40s, 80s
            wait = random.uniform(0, min(120, 10 * (2 ** attempt)))
            print(f"Overloaded (529), backing off {wait:.1f}s")
            time.sleep(wait)
            # Optionally downgrade to Haiku for better availability
            if attempt >= 2:
                messages = [{"role": "user", "content":
                    messages[-1]["content"] + "\n\nBe concise."}]

import time
import random
import anthropic
from dataclasses import dataclass, field

@dataclass
class RetryMetrics:
    total_requests: int = 0
    total_retries: int = 0
    rate_limit_hits: int = 0
    overload_hits: int = 0

    @property
    def retry_rate(self) -> float:
        if self.total_requests == 0:
            return 0.0
        return self.total_retries / self.total_requests

metrics = RetryMetrics()
client = anthropic.Anthropic(max_retries=0)

RETRY_RATE_ALERT_THRESHOLD = 0.05

def instrumented_call(messages: list, max_attempts: int = 6):
    metrics.total_requests += 1
    for attempt in range(max_attempts):
        try:
            return client.messages.create(
                model="claude-sonnet-4-6",
                max_tokens=512,
                messages=messages,
            )
        except anthropic.RateLimitError as e:
            metrics.total_retries += 1
            metrics.rate_limit_hits += 1
            if attempt == max_attempts - 1:
                raise
            wait = float(e.response.headers.get("retry-after", 2 ** attempt))
            time.sleep(wait + random.uniform(0, 0.5))
        except anthropic.OverloadedError:
            metrics.total_retries += 1
            metrics.overload_hits += 1
            if attempt == max_attempts - 1:
                raise
            time.sleep(random.uniform(0, min(60, 10 * 2 ** attempt)))

    if metrics.retry_rate > RETRY_RATE_ALERT_THRESHOLD:
        print(
            f"ALERT: retry rate {metrics.retry_rate:.1%} "
            f"(429s: {metrics.rate_limit_hits}, "
            f"529s: {metrics.overload_hits})"
        )
